function nexusPredictiveTrajectoryValues() {
  return ["improving", "stable", "worsening", "variable", "unknown"];
}

function nexusPredictiveConfidenceValues() {
  return ["high", "moderate", "low", "insufficient_data"];
}

function createPredictiveState(mode = "marketplace") {
  const adapter = NEXUS_PREDICTIVE_ADAPTERS[mode] || NEXUS_PREDICTIVE_ADAPTERS.marketplace;
  const now = new Date().toISOString();
  return {
    id: `nexus-${adapter.mode}-predictive-${Date.now()}`,
    mode: adapter.mode,
    title: adapter.title,
    createdAt: now,
    updatedAt: now,
    source: "nexus_multi_domain_predictive_intelligence_engine",
    localOnly: true,
    sandbox: Boolean(nexusDemoDataState?.loaded),
    expertEvaluationMode: true,
    records: [],
    trends: {},
    riskSignals: [],
    trajectory: [],
    scenarioSimulations: [],
    missingData: [],
    confidence: {},
    expertChecklist: [],
    reasoningTrace: [],
    expertSummary: {},
    receipts: []
  };
}

function parsePredictiveCommand(input = "", mode = "") {
  const adapter = NEXUS_PREDICTIVE_ADAPTERS[mode] || predictiveAdapterForCommand(input);
  const text = String(input || "");
  const lower = text.toLowerCase();
  const record = {
    id: `nexus-${adapter.mode}-predictive-record-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
    mode: adapter.mode,
    rawInput: text,
    parsedValue: text,
    recordType: "predictive_observation",
    timestamp: new Date().toISOString(),
    source: "natural_command",
    localOnly: true,
    entities: {
      commodity: /\bmaize|cassava|rice|tomato|beans|produce|product\b/i.exec(text)?.[0] || "",
      personOrOrg: /\bDemo Buyer One|buyer|seller|employer|provider|carrier|instructor|operator\b/i.exec(text)?.[0] || "",
      status: /\bdelayed|missing|closed|cancel|ready|risk|apply|training|draft|whatsapp|phone number\b/i.exec(text)?.[0] || ""
    },
    flags: {
      missing: /\bmissing|without|incomplete|no\b/i.test(lower),
      simulate: /\bsimulate\b/i.test(lower),
      summary: /\bsummary\b/i.test(lower),
      risk: /\brisk|assess|predict|readiness|ready\b/i.test(lower),
      cancelOrClosed: /\bcancel|closed|inactive\b/i.test(lower),
      confirmationNeeded: /\bsend|call|contact|whatsapp|payment|dispatch|submit|apply\b/i.test(lower)
    }
  };
  return { adapter, observation: record };
}

function predictiveAdapterForCommand(input = "") {
  const command = String(input || "");
  return Object.values(NEXUS_PREDICTIVE_ADAPTERS).find(adapter => adapter.commandPattern.test(command)) || null;
}

function isNexusMultiDomainPredictiveCommand(command = "") {
  return Boolean(predictiveAdapterForCommand(command));
}

function evaluatePredictiveSignal(mode = "", observation = {}, state = null) {
  const adapter = NEXUS_PREDICTIVE_ADAPTERS[mode] || NEXUS_PREDICTIVE_ADAPTERS.marketplace;
  const records = [...(state?.records || []), observation].filter(Boolean);
  const text = records.map(record => record.rawInput || "").join(" ").toLowerCase();
  const missing = new Set();
  const factors = [];
  let riskLevel = adapter.riskLevels[1] || "watch";
  let signalName = `${adapter.title.replace(" Modeler", "")} signal`;
  let trajectory = records.length >= 2 ? "variable" : "unknown";

  if (adapter.mode === "marketplace") {
    ["buyer identity", "seller identity", "quantity", "quality grade", "price expectation", "transport availability", "payment terms", "verification status"].forEach(item => { if (!new RegExp(item.split(" ")[0], "i").test(text)) missing.add(item); });
    factors.push(/maize|product|listing/.test(text) ? "Product/listing intent detected" : "Trade intent detected");
    if (/verification.*missing|buyer verification is missing/.test(text)) riskLevel = "needs_verification";
    else if (/cancel|closed/.test(text)) riskLevel = "high_risk";
    else if (/buyer|seller|sell|listing/.test(text)) riskLevel = missing.size > 5 ? "incomplete" : "market_ready";
    signalName = "Transaction readiness signal";
  }
  if (adapter.mode === "logistics") {
    ["tracking number", "carrier", "origin", "destination", "expected delivery date", "cold-chain status", "destination contact"].forEach(item => { if (!new RegExp(item.split(" ")[0], "i").test(text)) missing.add(item); });
    factors.push(/delayed/.test(text) ? "Delay report detected" : "Shipment/route intent detected");
    if (/cold storage fails|cold chain/.test(text)) riskLevel = "cold_chain_risk";
    else if (/delayed|delay/.test(text)) riskLevel = "elevated_delay_risk";
    else riskLevel = missing.size > 4 ? "incomplete" : "route_ready";
    signalName = "Shipment readiness and route risk signal";
  }
  if (adapter.mode === "workforce") {
    ["target role", "resume", "experience", "skills", "certifications", "availability", "employer requirements"].forEach(item => { if (!new RegExp(item.split(" ")[0], "i").test(text)) missing.add(item); });
    factors.push(/skills|training/.test(text) ? "Skill/training gap detected" : "Candidate application intent detected");
    if (/skills.*missing|skill/.test(text)) riskLevel = "skill_gap";
    else if (/certification|credential/.test(text)) riskLevel = "credential_gap";
    else riskLevel = missing.size > 4 ? "incomplete" : "job_ready";
    signalName = "Application readiness signal";
  }
  if (adapter.mode === "learning") {
    ["learning goal", "current skill level", "available time", "digital literacy", "prior training", "language needs", "assessment score"].forEach(item => { if (!new RegExp(item.split(" ")[0], "i").test(text)) missing.add(item); });
    factors.push(/study three days|learning plan/.test(text) ? "Study plan signal detected" : "Learning pathway intent detected");
    if (/completion risk/.test(text)) riskLevel = "completion_risk";
    else if (/skills|gap/.test(text)) riskLevel = "skill_gap";
    else riskLevel = missing.size > 4 ? "blocked_missing_data" : "learning_ready";
    signalName = "Learning pathway fit signal";
  }
  if (adapter.mode === "drone") {
    ["field location", "mission purpose", "operator readiness", "equipment readiness", "battery status", "weather status", "approval", "flight area"].forEach(item => { if (!new RegExp(item.split(" ")[0], "i").test(text)) missing.add(item); });
    factors.push(/weather|battery|approval/.test(text) ? "Operational readiness gap detected" : "Drone mission preparation intent detected");
    if (/approval/.test(text)) riskLevel = "needs_approval";
    else if (/weather is poor|battery readiness is missing/.test(text)) riskLevel = "elevated_operation_risk";
    else riskLevel = missing.size > 4 ? "incomplete" : "mission_ready";
    signalName = "Drone mission readiness signal";
  }
  if (adapter.mode === "communications") {
    ["recipient", "contact method", "phone/email/handle", "message purpose", "tone", "confirmation status", "privacy/sensitivity"].forEach(item => { if (!new RegExp(item.split("/")[0].split(" ")[0], "i").test(text)) missing.add(item); });
    factors.push(/whatsapp|call|send|provider/.test(text) ? "Communication handoff intent detected" : "Message draft readiness intent detected");
    if (/phone number is missing|missing.*contact/.test(text)) riskLevel = "blocked_missing_data";
    else if (/send|call|whatsapp|contact/.test(text)) riskLevel = "needs_confirmation";
    else riskLevel = missing.size > 4 ? "incomplete" : "draft_ready";
    signalName = "Message readiness signal";
  }

  const signal = {
    id: `nexus-${adapter.mode}-predictive-signal-${Date.now()}`,
    domain: adapter.mode,
    signalName,
    riskLevel,
    trajectory,
    confidenceLabel: missing.size > 5 ? "low" : missing.size ? "moderate" : "high",
    dataQuality: missing.size ? "partial local/sandbox context" : "usable local/sandbox context",
    explanation: `${adapter.title} evaluated structured local input for readiness, risk, missing data, and next safe action.`,
    contributingFactors: factors,
    missingData: Array.from(missing),
    recommendedReview: "Review the local predictive summary before any configured external action.",
    suggestedNextQuestions: adapter.examples.slice(0, 3),
    createdAt: new Date().toISOString()
  };
  return { adapter, records, signal };
}

function buildScenarioSimulations(mode = "", evaluation = {}) {
  const adapter = NEXUS_PREDICTIVE_ADAPTERS[mode] || evaluation.adapter || NEXUS_PREDICTIVE_ADAPTERS.marketplace;
  const labels = {
    marketplace: ["Transport is delayed", "Buyer verification is missing", "Payment terms are completed"],
    logistics: ["Shipment is delayed two days", "Cold storage fails", "Origin and destination are verified"],
    workforce: ["Training is completed", "Resume is missing experience", "Certification is added"],
    learning: ["Study happens three days per week", "Digital literacy is low", "Assessment score improves"],
    drone: ["Weather is poor", "Battery readiness is missing", "Approval is confirmed"],
    communications: ["Phone number is missing", "Message is confirmed", "Recipient and purpose are clear"]
  }[adapter.mode] || ["Missing data remains", "Required data is completed", "Review is confirmed"];
  return labels.map(label => ({
    scenario: label,
    projectedSignal: `${adapter.mode} predictive signal may ${/missing|fails|delayed|poor|low/i.test(label) ? "worsen or remain blocked" : "improve after review"}.`,
    reason: "Scenario projection uses local deterministic readiness signals and does not execute externally.",
    reviewNote: adapter.noClaims
  }));
}

function buildExpertChecklist(mode = "", evaluation = {}) {
  const adapter = NEXUS_PREDICTIVE_ADAPTERS[mode] || evaluation.adapter || NEXUS_PREDICTIVE_ADAPTERS.marketplace;
  return [
    "Input parsed",
    "Structured record created",
    "Risk/readiness signal generated",
    "Trajectory assigned",
    "Confidence/data quality assigned",
    "Contributing factors explained",
    "Missing data identified",
    "Scenario projection generated",
    "Expert summary available",
    "Receipt/timeline recorded",
    "Next safe action routed",
    "No external action falsely claimed"
  ].map(label => ({ label, checked: label === "No external action falsely claimed" || Boolean(evaluation.signal) || Boolean(adapter) }));
}

function buildReasoningTrace(mode = "", evaluation = {}) {
  const adapter = NEXUS_PREDICTIVE_ADAPTERS[mode] || evaluation.adapter || NEXUS_PREDICTIVE_ADAPTERS.marketplace;
  return [
    `Parsed command for ${adapter.title}.`,
    "Created a structured local/sandbox predictive record.",
    `Evaluated domains: ${adapter.domains.join(", ")}.`,
    `Assigned signal: ${evaluation.signal?.signalName || "predictive signal"} / ${evaluation.signal?.riskLevel || "watch"}.`,
    `Assigned trajectory: ${evaluation.signal?.trajectory || "unknown"}.`,
    `Assigned confidence: ${evaluation.signal?.confidenceLabel || "insufficient_data"}.`,
    "Identified missing data and contributing factors.",
    "Generated scenarios, expert checklist, summary, and receipt.",
    adapter.noClaims
  ];
}

function buildExpertSummary(mode = "", evaluation = {}, state = {}) {
  const adapter = NEXUS_PREDICTIVE_ADAPTERS[mode] || evaluation.adapter || NEXUS_PREDICTIVE_ADAPTERS.marketplace;
  const signal = evaluation.signal || state.riskSignals?.[0] || {};
  const text = [
    `${adapter.title.replace(" Modeler", "")} Summary`,
    "",
    `Mode:\n${adapter.mode}`,
    "",
    `Recent local records:\n${(state.records || []).slice(-5).map(record => record.rawInput).join("\n") || "No records captured yet."}`,
    "",
    `Risk/readiness signal:\n${signal.signalName || "Insufficient data"} - ${signal.riskLevel || "blocked_missing_data"}`,
    "",
    `Trajectory:\n${signal.trajectory || "unknown"}`,
    "",
    `Confidence/data quality:\n${signal.confidenceLabel || "insufficient_data"} / ${signal.dataQuality || "insufficient data"}`,
    "",
    `Contributing factors:\n${(signal.contributingFactors || []).join("\n") || "No contributing factors yet."}`,
    "",
    `Missing data:\n${(signal.missingData || []).join("\n") || "No major missing data flagged."}`,
    "",
    `Scenario projections:\n${(state.scenarioSimulations || []).map(item => `${item.scenario}: ${item.projectedSignal}`).join("\n")}`,
    "",
    `Important system note:\n${adapter.noClaims}`
  ].join("\n");
  return { title: `${adapter.title.replace(" Modeler", "")} Summary`, text, generatedAt: new Date().toISOString(), localOnly: true, noExternalExecutionAuthorized: true };
}

function recordPredictiveReceipt(mode = "", event = {}) {
  const adapter = NEXUS_PREDICTIVE_ADAPTERS[mode] || NEXUS_PREDICTIVE_ADAPTERS.marketplace;
  return {
    id: `nexus-${adapter.mode}-predictive-receipt-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
    eventType: event.eventType || "predictive_evaluation_completed",
    detail: event.detail || `${adapter.title} evaluated locally.`,
    happened: event.detail || `${adapter.title} evaluated locally.`,
    didNot: adapter.noClaims,
    createdAt: new Date().toISOString(),
    localOnly: true,
    expertEvaluationMode: true
  };
}

function routePredictiveCommand(input = "", source = "predictive-command") {
  const parsed = parsePredictiveCommand(input);
  if (!parsed.adapter) return false;
  const mode = parsed.adapter.mode;
  const currentState = {
    ...createPredictiveState(mode),
    ...(nexusMultiDomainPredictiveState[mode] || {})
  };
  const evaluation = evaluatePredictiveSignal(mode, parsed.observation, currentState);
  const state = {
    ...currentState,
    mode,
    title: parsed.adapter.title,
    updatedAt: new Date().toISOString(),
    records: evaluation.records,
    riskSignals: [evaluation.signal, ...(currentState.riskSignals || [])].slice(0, 20),
    trends: { latestTrajectory: evaluation.signal.trajectory, recordCount: evaluation.records.length },
    trajectory: [{ mode, trajectory: evaluation.signal.trajectory, createdAt: new Date().toISOString() }],
    missingData: evaluation.signal.missingData,
    confidence: { label: evaluation.signal.confidenceLabel, dataQuality: evaluation.signal.dataQuality },
    scenarioSimulations: buildScenarioSimulations(mode, evaluation),
    expertChecklist: buildExpertChecklist(mode, evaluation),
    reasoningTrace: buildReasoningTrace(mode, evaluation),
    receipts: []
  };
  state.expertSummary = buildExpertSummary(mode, evaluation, state);
  state.receipts = [
    recordPredictiveReceipt(mode, { eventType: "predictive_record_captured", detail: `${parsed.adapter.title} captured a local predictive record.` }),
    recordPredictiveReceipt(mode, { eventType: "predictive_signal_generated", detail: `${evaluation.signal.signalName}: ${evaluation.signal.riskLevel}.` }),
    ...(currentState.receipts || [])
  ].slice(0, 30);
  const maturityEntry = recordNexusPredictiveMaturityHistory(mode, input, state, parsed.observation);
  state.confidence = {
    label: maturityEntry.confidence.confidenceLabel,
    score: maturityEntry.confidence.confidenceScore,
    dataQuality: maturityEntry.confidence.dataQualityLabel,
    evidenceStrength: maturityEntry.confidence.evidenceStrength,
    uncertaintyReasons: maturityEntry.confidence.uncertaintyReasons
  };
  nexusMultiDomainPredictiveState = { ...nexusMultiDomainPredictiveState, [mode]: state };
  saveNexusRuntimeMemory();
  const mission = buildNexusMultiDomainPredictiveMission(mode, input, state, source);
  return setNexusAgenticCommandResult(mission, `${parsed.adapter.title} updated. Review snapshot, trajectory, factors, missing data, scenarios, checklist, reasoning trace, summary, and receipts.`);
}

function buildNexusMultiDomainPredictiveMission(mode = "", command = "", state = null, source = "predictive-command") {
  const adapter = NEXUS_PREDICTIVE_ADAPTERS[mode] || NEXUS_PREDICTIVE_ADAPTERS.marketplace;
  const signal = state?.riskSignals?.[0] || {};
  return {
    id: `nexus-${adapter.mode}-predictive-mission-${Date.now()}`,
    title: adapter.title,
    mode: adapter.missionMode,
    submode: `${adapter.mode}_predictive_intelligence_modeler`,
    goal: command,
    status: "predictive_support_ready",
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    userInput: command,
    source,
    sandbox: Boolean(nexusDemoDataState?.loaded),
    localOnly: true,
    expertEvaluationMode: true,
    collectedInfo: [`Signal: ${signal.riskLevel || "blocked_missing_data"}`, `Trajectory: ${signal.trajectory || "unknown"}`, `Confidence: ${state?.confidence?.label || "insufficient_data"}`],
    missingInfo: state?.missingData || [],
    suggestedQuestions: adapter.examples.slice(0, 4),
    nextStep: "Review the predictive summary and collect missing data before any gated external action.",
    riskLevel: /risk|blocked|needs|high/i.test(signal.riskLevel || "") ? "high" : "medium",
    confirmationRequired: false,
    confirmationStatus: "not_required_for_local_predictive_review",
    executionStatus: "completed_local_predictive_support",
    providerReadiness: "local_predictive_support_only",
    actionPlan: ["Parse input", "Create structured record", "Generate signal", "Explain reasoning", "Prepare next safe action"],
    receipts: state?.receipts || [],
    timeline: (state?.receipts || []).map(receipt => ({ at: receipt.createdAt, event: receipt.eventType, detail: receipt.detail })),
    relatedRecords: state?.records || [],
    outcome: { status: signal.riskLevel || "blocked_missing_data", verified: true, noExternalExecution: true },
    safetyNote: adapter.noClaims,
    actionType: `${adapter.mode}_predictive_modeler`
  };
}

function renderPredictivePanel(mode = "", state = null) {
  const adapter = NEXUS_PREDICTIVE_ADAPTERS[mode] || NEXUS_PREDICTIVE_ADAPTERS.marketplace;
  const panelState = state || nexusMultiDomainPredictiveState[mode] || createPredictiveState(mode);
  const signal = panelState.riskSignals?.[0] || {};
  return `
    <section class="nexus-predictive-panel" ${adapter.panelSelector}="true" data-nexus-predictive-mode="${escapeHtml(adapter.mode)}" data-local-only="true" data-no-external-execution="true" aria-label="${escapeHtml(translateText(adapter.title))}">
      <header class="nexus-chronic-predictive-header">
        <span class="eyebrow">${escapeHtml(translateText("Multi-domain predictive intelligence"))}</span>
        <h3>${escapeHtml(translateText(adapter.title))}</h3>
        <p>${escapeHtml(translateText(`${adapter.title} structures local input, detects risk/readiness signals, explains reasoning, and prepares the next safe action. ${adapter.noClaims}`))}</p>
      </header>
      <div class="nexus-chronic-predictive-grid">
        <article class="nexus-predictive-snapshot" data-nexus-predictive-snapshot="true"><strong>${escapeHtml(translateText("Current Snapshot"))}</strong><span>Signal: ${escapeHtml(signal.signalName || "No signal yet")}</span><span>Risk/readiness: ${escapeHtml(signal.riskLevel || "blocked_missing_data")}</span><span>Trajectory: ${escapeHtml(signal.trajectory || "unknown")}</span><span>Confidence: ${escapeHtml(panelState.confidence?.label || "insufficient_data")}</span><span>Records: ${escapeHtml(String(panelState.records?.length || 0))}</span></article>
        <article class="nexus-predictive-trends" data-nexus-predictive-trends="true"><strong>${escapeHtml(translateText("Trends / Trajectory"))}</strong><span>Latest trajectory: ${escapeHtml(panelState.trends?.latestTrajectory || "unknown")}</span><span>Trajectory values: ${escapeHtml(nexusPredictiveTrajectoryValues().join(", "))}</span><span>Confidence values: ${escapeHtml(nexusPredictiveConfidenceValues().join(", "))}</span></article>
        <article class="nexus-predictive-factors" data-nexus-predictive-factors="true"><strong>${escapeHtml(translateText("Contributing Factors"))}</strong>${(signal.contributingFactors?.length ? signal.contributingFactors : ["No contributing factors yet. Add domain context."]).map(item => `<span>${escapeHtml(item)}</span>`).join("")}</article>
        <article class="nexus-predictive-missing-data" data-nexus-predictive-missing-data="true"><strong>${escapeHtml(translateText("Missing Data"))}</strong>${(panelState.missingData?.length ? panelState.missingData : ["No major missing data flagged yet."]).map(item => `<span>${escapeHtml(item)}</span>`).join("")}</article>
      </div>
      <div class="nexus-chronic-predictive-grid">
        <article class="nexus-predictive-scenarios" data-nexus-predictive-scenarios="true"><strong>${escapeHtml(translateText("Scenario Simulator"))}</strong>${(panelState.scenarioSimulations || []).map(item => `<span><b>${escapeHtml(item.scenario)}</b>: ${escapeHtml(item.projectedSignal)}</span>`).join("")}</article>
        <article class="nexus-predictive-checklist" data-nexus-predictive-checklist="true"><strong>${escapeHtml(translateText("Expert Checklist"))}</strong>${(panelState.expertChecklist || []).map(item => `<span>${item.checked ? "Checked" : "Needs context"}: ${escapeHtml(item.label)}</span>`).join("")}</article>
        <article class="nexus-predictive-reasoning-trace" data-nexus-predictive-reasoning-trace="true"><strong>${escapeHtml(translateText("Reasoning Trace"))}</strong>${(panelState.reasoningTrace || []).map((item, index) => `<span>${index + 1}. ${escapeHtml(item)}</span>`).join("")}</article>
        <article class="nexus-predictive-receipts" data-nexus-predictive-receipts="true"><strong>${escapeHtml(translateText("Receipts / Timeline"))}</strong>${(panelState.receipts?.length ? panelState.receipts : [{ detail: "No predictive receipts yet." }]).slice(0, 6).map(item => `<span>${escapeHtml(item.detail || item.happened || "Receipt recorded locally.")}</span>`).join("")}</article>
      </div>
      ${renderNexusPredictiveMaturityInline(adapter.mode)}
      <article class="nexus-predictive-summary" data-nexus-predictive-summary="true">
        <strong>${escapeHtml(translateText("Expert Summary"))}</strong>
        <pre>${escapeHtml(panelState.expertSummary?.text || "Enter a predictive command to generate a summary.")}</pre>
      </article>
      <article class="nexus-predictive-command-examples" data-nexus-predictive-command-examples="true">
        <strong>${escapeHtml(translateText("Command Examples"))}</strong>
        <div>${adapter.examples.map(command => `<button type="button" data-nexus-command-prefill="${escapeHtml(command)}">${escapeHtml(command)}</button>`).join("")}</div>
      </article>
    </section>
  `;
}

function renderNexusPredictiveIntelligenceIndex() {
  const cards = [
    ["chronic", "Chronic Health", nexusChronicPredictiveModelerState?.riskSignals?.[0], nexusChronicPredictiveModelerState?.receipts?.length || 0, "Nexus, show my chronic risk trend."],
    ["agriculture", "Agriculture", nexusAgriculturePredictiveModelerState?.riskSignals?.[0], nexusAgriculturePredictiveModelerState?.receipts?.length || 0, "Nexus, show my field risk trend."],
    ...Object.values(NEXUS_PREDICTIVE_ADAPTERS).map(adapter => [adapter.mode, adapter.title.replace(" Predictive Intelligence Modeler", ""), nexusMultiDomainPredictiveState[adapter.mode]?.riskSignals?.[0], nexusMultiDomainPredictiveState[adapter.mode]?.receipts?.length || 0, adapter.examples[0]])
  ];
  return `
    <section class="nexus-predictive-panel" data-nexus-platform-predictive-index="true" aria-label="${escapeHtml(translateText("Nexus Predictive Intelligence Engine"))}">
      <header class="nexus-chronic-predictive-header"><span class="eyebrow">${escapeHtml(translateText("Predictive Intelligence"))}</span><h3>${escapeHtml(translateText("Nexus Predictive Intelligence Engine"))}</h3><p>${escapeHtml(translateText("Open predictive engines for chronic health, agriculture, marketplace, logistics, workforce, learning, drone operations, and communications."))}</p></header>
      <div class="nexus-chronic-predictive-grid">${cards.map(([mode, label, signal, receipts, command]) => `<article data-nexus-predictive-index-card="${escapeHtml(mode)}"><strong>${escapeHtml(label)}</strong><span>Latest signal: ${escapeHtml(signal?.riskLevel || "not started")}</span><span>Trajectory: ${escapeHtml(signal?.trajectory || "unknown")}</span><span>Receipts: ${escapeHtml(String(receipts))}</span><button type="button" data-nexus-command-prefill="${escapeHtml(command)}">${escapeHtml(translateText("Open modeler"))}</button></article>`).join("")}</div>
    </section>
  `;
}

function setNexusAgenticCommandResult(mission, message = "") {
  const polishedMessage = applyNexusExperiencePolishToMission(mission, mission.goal || mission.command || "", message);
  const latestReceipt = mission.receipts?.[0] || nexusAgenticCommandLocalMemory.receipts?.[0] || null;
  nexusAgenticBrainLastResult = {
    ok: true,
    status: mission.executionStatus || mission.status,
    mode: mission.mode,
    message: polishedMessage || message || `Nexus created ${mission.title}.`,
    preparedCards: [{
      type: "agentic_command_mission",
      title: mission.title,
      status: mission.status,
      localOnly: true,
      agenticCommandRuntime: true,
      missingInfo: mission.missingInfo,
      collectedInfo: mission.collectedInfo,
      confirmationRequired: mission.confirmationRequired,
      receiptId: latestReceipt?.id || "",
      nextBestQuestion: mission.nextBestQuestion,
      confidenceExplanation: mission.confidenceExplanation,
      suggestedNextActions: mission.suggestedNextActions,
      receiptMessage: mission.receiptMessage
    }],
    mission,
    noExecutionAuthorized: mission.executionStatus !== "executed_with_receipt",
    localOnly: true,
    source: "nexus_agentic_command_runtime"
  };
  upsertNexusAgenticMission(mission);
  nexusActiveWorkflowState = null;
  setNexusIntentDrivenWorkflowStatusForCommand(mission.goal || mission.command || "", {
    source: "agentic-result-intent-router"
  });
  saveNexusRuntimeMemory();
  renderUserWorkspace();
  const missingCount = Array.isArray(mission.missingInfo) ? mission.missingInfo.length : 0;
  setNexusPresenceState(mission.confirmationRequired ? NEXUS_PRESENCE_STATES.AWAITING_CONFIRMATION : (missingCount ? NEXUS_PRESENCE_STATES.AWAITING_FOLLOWUP : NEXUS_PRESENCE_STATES.COMPLETED_LOCAL), {
    lastUserInput: mission.goal || mission.command || nexusPresenceState.lastUserInput,
    lastResponse: polishedMessage || message || nexusAgenticBrainLastResult.message,
    nextQuestion: mission.nextBestQuestion || mission.nextStep || (missingCount ? "I need one more detail." : "Ask Nexus what you need next."),
    activeMission: mission.title || mission.mode || "Nexus local mission"
  });
  return true;
}

function submitNexusAgenticCommandRuntime(command = "", input = null, source = "command-submit", event = null) {
  const normalizedCommand = String(command || "").trim();
  if (!shouldNexusAgenticCommandRuntimeHandle(normalizedCommand) && !isNexusPersistentMemoryCommand(normalizedCommand) && !isNexusPredictiveMaturityCommand(normalizedCommand) && !isNexusChronicPredictiveModelerCommand(normalizedCommand) && !isNexusAgriculturePredictiveModelerCommand(normalizedCommand) && !isNexusMultiDomainPredictiveCommand(normalizedCommand)) return false;
  const handled = runNexusAgenticCommandRuntime(normalizedCommand, { source });
  if (!handled) return false;
  event?.preventDefault?.();
  event?.stopPropagation?.();
  event?.stopImmediatePropagation?.();
  if (input) input.value = normalizedCommand;
  setCommandInputs(normalizedCommand);
  return true;
}

function getNexusMemory(scope = "missions") {
  const normalized = String(scope || "missions").toLowerCase();
  if (/\bbuyer/.test(normalized)) return nexusAgenticCommandLocalMemory.buyers || [];
  if (/\bseller/.test(normalized)) return nexusAgenticCommandLocalMemory.sellers || [];
  if (/\breceipt/.test(normalized)) return nexusAgenticCommandLocalMemory.receipts || [];
  if (/\bintake|health/.test(normalized)) return nexusAgenticCommandLocalMemory.healthIntakes || [];
  if (/\breading|rpm|rtm|blood pressure/.test(normalized)) return nexusAgenticCommandLocalMemory.chronicReadings || [];
  if (/\bshipment/.test(normalized)) return nexusAgenticCommandLocalMemory.shipmentRecords || nexusAgenticCommandLocalMemory.shipments || [];
  if (/\broute/.test(normalized)) return nexusAgenticCommandLocalMemory.tradeRoutePlans || [];
  if (/\bemployer/.test(normalized)) return nexusAgenticCommandLocalMemory.employers || [];
  if (/\bjob|application/.test(normalized)) return nexusAgenticCommandLocalMemory.jobApplicationDrafts || nexusAgenticCommandLocalMemory.employmentRecords || [];
  if (/\blearning/.test(normalized)) return nexusAgenticCommandLocalMemory.learningPlans || [];
  if (/\bdrone/.test(normalized)) return nexusAgenticCommandLocalMemory.droneMissions || [];
  if (/\bmessage|communication|whatsapp|telegram|email|call/.test(normalized)) return nexusAgenticCommandLocalMemory.communicationDrafts || [];
  return nexusAgenticCommandMissions || nexusAgenticCommandLocalMemory.missions || [];
}

function nexusPersistentMemoryStore() {
  if (!nexusPersistentMemoryService) return null;
  return nexusPersistentMemoryService.createMemoryStore(nexusPersistentMemoryState, { persistenceScope: "local_browser", ownerRole: nexusUserExperienceRole || "Standard User" });
}

function syncNexusPersistentMemoryStore(store) {
  if (!store) return null;
  nexusPersistentMemoryState = store.snapshot();
  saveNexusRuntimeMemory();
  return nexusPersistentMemoryState;
}

function inferNexusPersistentMemoryType(command = "") {
  const text = String(command || "").toLowerCase();
  if (/\b(deceased|inactive patient|patient intake|symptom|diabetes|hypertension|obesity|blood pressure|bp|rpm|rtm|chronic)\b/.test(text)) return "health_patient_intake";
  if (/\b(farmer profile|farm profile|crop issue|crop|field|pest|disease|soil|irrigation|drone mission link)\b/.test(text)) return "crop_issue_record";
  if (/\b(buyer)\b/.test(text)) return "buyer_profile";
  if (/\b(seller|out of business)\b/.test(text)) return "seller_profile";
  if (/\b(listing|marketplace|agritrade)\b/.test(text)) return "marketplace_listing";
  if (/\b(transaction|payment|cancellation|add-on|addon|order|dispute)\b/.test(text)) return "transaction_record";
  if (/\b(shipment|delivery|route|eta|proof of delivery|tracking)\b/.test(text)) return "shipment_record";
  if (/\b(learner|course|certification|training progress|learning)\b/.test(text)) return "learning_progress";
  if (/\b(applicant|job readiness|resume|interview|workforce|employer)\b/.test(text)) return /\bemployer\b/.test(text) ? "employer_profile" : "workforce_applicant";
  if (/\b(provider|clinic|pharmacy|mobile clinic)\b/.test(text)) return /\bpharmacy\b/.test(text) ? "pharmacy_profile" : /\bmobile clinic\b/.test(text) ? "mobile_clinic_profile" : /\bclinic\b/.test(text) ? "clinic_profile" : "provider_profile";
  if (/\b(drone|field survey|no-fly|operator)\b/.test(text)) return "drone_mission_record";
  if (/\bpredictive|risk signal|intelligence summary\b/.test(text)) return "predictive_intelligence_record";
  return "general_memory_record";
}

function inferNexusPersistentMemorySourceMode(type = "") {
  if (/health|chronic|patient/.test(type)) return "health";
  if (/farmer|farm|crop/.test(type)) return "agriculture";
  if (/buyer|seller|marketplace|transaction/.test(type)) return "marketplace";
  if (/shipment|route/.test(type)) return "logistics";
  if (/learning/.test(type)) return "learning";
  if (/workforce|employer/.test(type)) return "workforce";
  if (/provider|clinic|pharmacy|mobile/.test(type)) return "provider_access";
  if (/drone/.test(type)) return "drone";
  if (/predictive/.test(type)) return "predictive_intelligence";
  return "standard_user";
}

function nexusPersistentMemoryTitle(type = "", command = "") {
  const label = type.split("_").filter(Boolean).map(part => part[0]?.toUpperCase() + part.slice(1)).join(" ");
  const compact = String(command || "").replace(/^nexus,?\s*/i, "").trim();
  return compact ? `${label}: ${compact.slice(0, 72)}` : label;
}

function isNexusPersistentMemoryCommand(command = "") {
  return /\b(memory|memories|saved records?|save .*(record|profile|listing|transaction|shipment|mission|intake)|remember this|save this|update .*record|archive .*record|mark .*inactive|mark .*deceased|out of business|clear local demo records|show .*records?|show receipts|predictive context)\b/i.test(String(command || ""));
}

function routeNexusPersistentMemoryCommand(command = "", source = "persistent-memory-command") {
  const store = nexusPersistentMemoryStore();
  if (!store) return false;
  const text = String(command || "").trim();
  const lower = text.toLowerCase();
  let result;
  if (/\bclear local demo records\b/.test(lower)) {
    const records = store.snapshot().records;
    records.forEach(record => store.deleteLocalRecord(record.id, true));
    result = { ok: true, action: "clear_local_demo_records", records: [], receipt: store.snapshot().receipts[0] };
  } else if (/\b(show|list|open|view).*(memory|memories|saved records?|records)\b/.test(lower)) {
    result = { ok: true, action: "list_records", records: store.snapshot().records, receipt: null };
  } else if (/\b(show|view).*receipts?\b/.test(lower)) {
    result = { ok: true, action: "list_receipts", records: store.snapshot().records, receipts: store.snapshot().receipts, receipt: null };
  } else if (/\bpredictive context\b/.test(lower)) {
    result = { ok: true, action: "predictive_context", records: store.predictiveContext().activeRecords, predictiveContext: store.predictiveContext(), receipt: null };
  } else if (/\b(mark|archive).*(deceased|inactive|out of business|closed|archive)\b/.test(lower)) {
    const latest = store.snapshot().records[0];
    if (!latest) {
      result = store.createRecord({
        type: inferNexusPersistentMemoryType(text),
        title: nexusPersistentMemoryTitle(inferNexusPersistentMemoryType(text), text),
        status: /deceased/.test(lower) ? "deceased" : /out of business|closed/.test(lower) ? "closed" : "inactive",
        sourceMode: inferNexusPersistentMemorySourceMode(inferNexusPersistentMemoryType(text)),
        payload: { command: text, note: "Archived/inactivated from command.", missingData: [] },
        riskLevel: /deceased|patient|health/.test(lower) ? "sensitive" : "moderate"
      });
    } else {
      result = store.archiveRecord(latest.id, /deceased/.test(lower) ? "deceased" : /out of business|closed/.test(lower) ? "closed" : "inactive", text);
    }
  } else if (/\bupdate .*record|save update|add note\b/.test(lower)) {
    const latest = store.snapshot().records[0];
    result = latest
      ? store.updateRecord(latest.id, { payload: { ...(latest.payload || {}), lastUpdateCommand: text }, status: latest.status || "active" })
      : store.createRecord({ type: inferNexusPersistentMemoryType(text), title: nexusPersistentMemoryTitle(inferNexusPersistentMemoryType(text), text), payload: { command: text }, sourceMode: inferNexusPersistentMemorySourceMode(inferNexusPersistentMemoryType(text)) });
  } else {
    const type = inferNexusPersistentMemoryType(text);
    const sourceMode = inferNexusPersistentMemorySourceMode(type);
    result = store.createRecord({
      type,
      title: nexusPersistentMemoryTitle(type, text),
      status: /queued/.test(lower) ? "queued" : /payment pending/.test(lower) ? "payment_pending" : "active",
      sourceMode,
      payload: {
        command: text,
        missingData: /crop/.test(type) ? ["crop type", "location", "field photo", "timeline", "symptoms"] : [],
        productionDatabaseActive: false,
        note: "Saved in browser-local Nexus memory."
      },
      riskLevel: /health|transaction|shipment|provider|pharmacy/.test(type) ? "moderate" : "low"
    });
  }
  syncNexusPersistentMemoryStore(store);
  const snapshot = store.snapshot();
  const mission = {
    id: `nexus-persistent-memory-${Date.now()}`,
    title: "Memory & Records",
    mode: "activity-receipts",
    submode: "persistent_memory_layer",
    goal: text,
    status: "completed_local",
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    userInput: text,
    source,
    sandbox: Boolean(nexusDemoDataState?.loaded),
    localOnly: true,
    collectedInfo: [
      `Records: ${snapshot.records.length}`,
      `Receipts: ${snapshot.receipts.length}`,
      snapshot.status?.message || "Local memory active. Production database not connected."
    ],
    missingInfo: snapshot.status?.database?.configured ? [] : ["Production database credentials are not configured."],
    suggestedQuestions: ["Show saved records.", "Show receipts.", "Show predictive context."],
    nextStep: "Review, update, archive, or use saved records for local predictive planning.",
    riskLevel: "low",
    confirmationRequired: false,
    confirmationStatus: "not_required",
    executionStatus: "completed_local",
    providerReadiness: snapshot.status?.persistenceScope || "local_browser",
    actionPlan: ["Save/read local memory.", "Create a receipt.", "Keep production database status truthful."],
    receipts: result.receipt ? [result.receipt] : [],
    timeline: [{ at: new Date().toISOString(), event: result.action || "persistent_memory", detail: "Persistent memory command handled locally." }],
    relatedRecords: snapshot.records.slice(0, 10),
    outcome: { status: "local_memory_updated", verified: true, noExternalExecution: true },
    safetyNote: "Local memory is not a production medical, financial, legal, payment, provider, shipment, drone, or emergency record system unless production database and compliance controls are configured.",
    actionType: "persistent_memory"
  };
  return setNexusAgenticCommandResult(mission, snapshot.status?.message || "Local memory active. Production database not connected.");
}

function renderNexusPersistentMemoryPanel() {
  const store = nexusPersistentMemoryStore();
  const snapshot = store ? store.snapshot() : nexusPersistentMemoryState;
  const status = snapshot.status || {};
  const records = snapshot.records || [];
  const receipts = snapshot.receipts || [];
  const active = records.filter(record => !/archived|inactive|deceased|closed|cancelled/i.test(record.status));
  const archived = records.filter(record => /archived|inactive|deceased|closed|cancelled/i.test(record.status));
  return `
    <section class="nexus-predictive-panel" data-nexus-persistent-memory-layer="true" data-persistence-scope="${escapeHtml(status.persistenceScope || "local_browser")}" aria-label="${escapeHtml(translateText("Memory and Records"))}">
      <header class="nexus-chronic-predictive-header">
        <span class="eyebrow">${escapeHtml(translateText("Persistent Memory"))}</span>
        <h3>${escapeHtml(translateText("Memory & Records"))}</h3>
        <p>${escapeHtml(translateText(status.message || "Local memory active. Production database not connected."))}</p>
        <small>${escapeHtml(translateText("Local memory is not a production medical, financial, legal, provider, payment, shipment, drone, or emergency record system unless production database and compliance controls are configured."))}</small>
      </header>
      <div class="nexus-chronic-predictive-grid">
        <article data-nexus-memory-status-card="true"><strong>${escapeHtml(translateText("Memory Status"))}</strong><span>Persistence: ${escapeHtml(status.persistenceScope || "local_browser")}</span><span>Database: ${escapeHtml(status.database?.configured ? "configured" : "not connected")}</span><span>Saved records: ${escapeHtml(String(records.length))}</span><span>Active: ${escapeHtml(String(active.length))} / Archived: ${escapeHtml(String(archived.length))}</span></article>
        <article data-nexus-memory-recent-records="true"><strong>${escapeHtml(translateText("Recent Records"))}</strong>${(records.length ? records : [{ title: "No saved records yet", type: "memory", status: "empty" }]).slice(0, 6).map(record => `<span>${escapeHtml(record.title || record.name)} - ${escapeHtml(record.type)} - ${escapeHtml(record.status)}</span>`).join("")}</article>
        <article data-nexus-memory-recent-receipts="true"><strong>${escapeHtml(translateText("Recent Receipts"))}</strong>${(receipts.length ? receipts : [{ result: "No memory receipts yet." }]).slice(0, 6).map(receipt => `<span>${escapeHtml(receipt.result || receipt.action || "Receipt")}</span>`).join("")}</article>
        <article data-nexus-memory-actions="true"><strong>${escapeHtml(translateText("Safe Memory Actions"))}</strong>${["Save patient intake memory.", "Save crop issue record.", "Save buyer profile.", "Save shipment record.", "Show saved records.", "Show predictive context.", "Archive this record.", "Clear local demo records."].map(command => `<button type="button" data-nexus-command-prefill="${escapeHtml(command)}">${escapeHtml(translateText(command))}</button>`).join("")}</article>
      </div>
    </section>
  `;
}

function saveNexusMemory(record = {}) {
  const mission = record.mission || record;
  if (!mission?.id) return null;
  upsertNexusAgenticMission(mission);
  saveNexusRuntimeMemory();
  return mission;
}

function updateNexusMemory(recordId = "", updates = {}) {
  const mission = nexusAgenticCommandMissions.find(item => item.id === recordId) || nexusAgenticCommandMissions[0] || null;
  if (!mission) return null;
  Object.assign(mission, updates, { updatedAt: new Date().toISOString() });
  mission.timeline.unshift({ at: mission.updatedAt, event: "memory_updated", detail: "Local/sandbox memory was updated. No external system was changed." });
  upsertNexusAgenticMission(mission);
  saveNexusRuntimeMemory();
  return mission;
}

function deactivateNexusMemory(recordId = "", reason = "") {
  return updateNexusMemory(recordId, {
    status: "archived",
    executionStatus: "deactivated_locally",
    outcome: { status: "deactivated_locally", verified: true, noExternalExecution: true },
    nextStep: reason || "Record is inactive locally. Review before creating a replacement."
  });
}

function deleteNexusMemoryWithConfirmation(recordId = "", reason = "") {
  const mission = nexusAgenticCommandMissions.find(item => item.id === recordId) || nexusAgenticCommandMissions[0] || null;
  if (!mission) return false;
  mission.status = "needs_confirmation";
  mission.executionStatus = "delete_confirmation_required";
  mission.confirmationRequired = true;
  mission.confirmationStatus = "required";
  mission.nextStep = reason || "Confirm deletion or choose mark inactive/closed instead.";
  mission.timeline.unshift({ at: new Date().toISOString(), event: "delete_confirmation_required", detail: "Delete requires explicit confirmation." });
  return setNexusAgenticCommandResult(mission, "Deletion requires confirmation. Nexus recommends marking the record inactive/closed before hard delete.");
}

function buildNexusMemoryResult(scope = "missions", command = "") {
  const records = getNexusMemory(scope);
  const label = String(scope || "missions");
  const mission = {
    id: `nexus-memory-${label.replace(/\W+/g, "-")}-${Date.now()}`,
    title: `${label.replace(/\b\w/g, letter => letter.toUpperCase())} memory`,
    mode: "activity-receipts",
    submode: "memory_retrieval",
    goal: command || `Show ${label}`,
    status: "completed_local",
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    userInput: command,
    source: "nexus_brain_memory",
    sandbox: Boolean(nexusDemoDataState?.loaded),
    localOnly: true,
    collectedInfo: records.length ? records.slice(0, 5).map(item => `${item.title || item.label || item.id}: ${item.status || item.value || "local record"}`) : [],
    missingInfo: records.length ? [] : [`No ${label} local/sandbox records found yet.`],
    suggestedQuestions: ["Continue that mission.", "What is still missing?", "Show receipts."],
    nextStep: records.length ? "Choose a record to continue, update, mark inactive, or prepare a safe handoff." : "Create a local mission or record first.",
    riskLevel: "low",
    confirmationRequired: false,
    confirmationStatus: "not_required",
    executionStatus: "completed_local",
    providerReadiness: "local_ready",
    actionPlan: ["Read local/sandbox memory.", "Show what Nexus knows.", "Avoid claiming cloud or provider storage."],
    receipts: [],
    timeline: [{ at: new Date().toISOString(), event: "memory_read", detail: `Read ${records.length} ${label} local/sandbox record(s).` }],
    relatedRecords: records.slice(0, 10),
    outcome: { status: "local_memory_read", verified: true, noExternalExecution: true },
    safetyNote: "Memory shown here is local/sandbox state unless a real cloud persistence provider is configured and confirmed.",
    actionType: "show"
  };
  return setNexusAgenticCommandResult(mission, records.length ? `I found ${records.length} ${label} local/sandbox record(s).` : `I do not have ${label} local/sandbox records yet.`);
}

function continueNexusAgenticMission(command = "") {
  const mission = nexusActiveWorkflowState?.agenticMission || nexusAgenticCommandMissions[0] || null;
  if (!mission) return false;
  mission.updatedAt = new Date().toISOString();
  mission.timeline.unshift({ at: mission.updatedAt, event: "mission_continued", detail: command || "User asked to continue the mission." });
  mission.nextStep = mission.missingInfo?.length ? `Collect: ${mission.missingInfo.slice(0, 3).join(", ")}.` : "Review the prepared local packet or confirm the next gated step.";
  return setNexusAgenticCommandResult(mission, `Continuing ${mission.title}. ${mission.nextStep}`);
}

function confirmNexusAgenticMission(command = "") {
  const mission = nexusActiveWorkflowState?.agenticMission || nexusAgenticCommandMissions[0] || null;
  if (!mission) return false;
  mission.confirmationStatus = "confirmed_for_local_preparation_only";
  mission.executionStatus = mission.riskLevel === "high" ? "queued_or_prepared_not_sent" : "completed_locally";
  mission.status = mission.riskLevel === "high" ? "queued" : "completed_local";
  mission.outcome = { status: mission.executionStatus, verified: true, noExternalExecution: true };
  mission.updatedAt = new Date().toISOString();
  const receipt = nexusAgenticCommandReceipt(mission, "Confirmation captured for local preparation/review.", "Nexus did not send, call, pay, book, dispatch, share location, contact a provider, diagnose, prescribe, or execute externally.");
  mission.receipts.unshift(receipt);
  mission.timeline.unshift({ at: receipt.createdAt, event: "confirmation_recorded", detail: receipt.didNot });
  return setNexusAgenticCommandResult(mission, "Confirmation was recorded for the local mission. External execution remains blocked until provider credentials, consent, approval, and audit gates are complete.");
}

function cancelNexusAgenticMission(command = "") {
  const mission = nexusActiveWorkflowState?.agenticMission || nexusAgenticCommandMissions[0] || null;
  if (!mission) return false;
  mission.status = "canceled";
  mission.executionStatus = "canceled_locally";
  mission.outcome = { status: "canceled_locally", verified: true, noExternalExecution: true };
  mission.updatedAt = new Date().toISOString();
  const receipt = nexusAgenticCommandReceipt(mission, "Mission was cancelled locally.", "No transaction, provider handoff, shipment, message, call, payment, or health action was executed.");
  mission.receipts.unshift(receipt);
  mission.timeline.unshift({ at: receipt.createdAt, event: "mission_cancelled", detail: receipt.happened });
  return setNexusAgenticCommandResult(mission, `${mission.title} was cancelled locally. No external action occurred.`);
}

function showNexusAgenticMissionStatus(command = "") {
  const mission = nexusActiveWorkflowState?.agenticMission || nexusAgenticCommandMissions[0] || null;
  if (!mission) return false;
  const missing = mission.missingInfo?.length ? mission.missingInfo.join(", ") : "nothing obvious for local preparation";
  const receipt = mission.receipts?.[0] || nexusAgenticCommandLocalMemory.receipts?.find?.(item => item.missionId === mission.id);
  const mode = nexusExperienceModeFromMission(mission);
  return setNexusAgenticCommandResult(mission, `What happened: ${receipt?.happened || mission.receiptMessage || "Nexus has a local mission record."} What did not happen: ${receipt?.didNot || "No external action was executed."} Confidence: ${mission.confidenceExplanation || getNexusExperienceConfidenceExplanation(mode, mission)}. Still missing: ${missing}. Next: ${mission.nextBestQuestion || mission.nextStep || getNextBestQuestion(mode, mission.missingInfo, mission)}`);
}

function runNexusAgenticCommandRuntime(command = "", options = {}) {
  if (isNexusPersistentMemoryCommand(command)) return routeNexusPersistentMemoryCommand(command, options.source || "agentic-command-runtime");
  if (isNexusPredictiveMaturityCommand(command)) return routeNexusPredictiveMaturityCommand(command, options.source || "agentic-command-runtime");
  if (isNexusMultiDomainPredictiveCommand(command)) return routePredictiveCommand(command, options.source || "agentic-command-runtime");
  if (isNexusAgriculturePredictiveModelerCommand(command)) return applyNexusAgriculturePredictiveCommand(command, options);
  if (isNexusChronicPredictiveModelerCommand(command)) {
    setNexusIntentDrivenWorkflowStatusForCommand(command, {
      ...options,
      source: options.source || "chronic-predictive-intent-router"
    });
    return applyNexusChronicPredictiveCommand(command, options);
  }
  const intent = parseNexusAgenticCommandIntent(command);
  if (!intent) return false;
  if (intent.actionType === "continue") return continueNexusAgenticMission(command);
  if (intent.actionType === "confirm") return confirmNexusAgenticMission(command);
  if (intent.actionType === "cancel") return cancelNexusAgenticMission(command);
  if (intent.actionType === "show") {
    if (/\bbuyers?\b/i.test(command)) return buildNexusMemoryResult("buyers", command);
    if (/\bsellers?\b/i.test(command)) return buildNexusMemoryResult("sellers", command);
    if (/\breceipts?\b|what happened|last action|did it send/i.test(command)) {
      const receipts = getNexusMemory("receipts");
      return receipts.length ? buildNexusMemoryResult("receipts", command) : showNexusAgenticMissionStatus(command);
    }
    if (/\blast intake|intake|health/i.test(command)) return buildNexusMemoryResult("health intakes", command);
    if (/\bsandbox missions?|demo missions?/i.test(command)) return buildNexusMemoryResult("missions", command);
    return showNexusAgenticMissionStatus(command);
  }
  if (intent.actionType === "update") {
    const mission = buildNexusAgenticMissionFromIntent(intent, command);
    mission.status = "needs_information";
    mission.executionStatus = "local_update_draft";
    mission.nextStep = "Tell Nexus which local record to update and the exact new detail. External systems will not be changed.";
    mission.timeline.unshift({ at: new Date().toISOString(), event: "update_draft_created", detail: "Local update draft created; no external record changed." });
    return setNexusAgenticCommandResult(mission, "I prepared a local update draft. I need the exact record and new detail before changing local memory.");
  }
  if (intent.actionType === "mark_closed") {
    const mission = buildNexusAgenticMissionFromIntent(intent, command);
    mission.status = "needs_confirmation";
    mission.executionStatus = "mark_closed_confirmation_required";
    mission.nextStep = "Confirm before Nexus marks this local/sandbox record closed. No marketplace, provider, shipment, or transaction system will be contacted.";
    return setNexusAgenticCommandResult(mission, "Marking a record closed requires confirmation. Nexus will only update local/sandbox memory.");
  }
  const mission = buildNexusAgenticMissionFromIntent(intent, command);
  if (intent.actionType === "delete") {
    mission.status = "needs_confirmation";
    mission.executionStatus = "delete_confirmation_required";
    mission.confirmationRequired = true;
    mission.confirmationStatus = "required";
    mission.nextStep = "Confirm before Nexus marks any local record inactive or deletes it. Nexus will explain impact first.";
  }
  const didRemember = intent.actionType === "remember";
  const message = didRemember
    ? `${mission.title} started and a local memory record was prepared. No external action occurred.`
    : `I understood that you want to: ${mission.goal}. I created a local mission and listed what is still missing.`;
  return setNexusAgenticCommandResult(mission, message);
}

function parseNexusCommand(input, context = {}) {
  return parseNexusAgenticCommandIntent(input, context);
}

function resolveNexusIntent(parsed, context = {}) {
  return {
    ...(parsed || {}),
    context,
    resolvedAt: new Date().toISOString(),
    executionAuthority: false,
    noExternalExecutionAuthorized: true
  };
}

function classifyNexusMode(intent) {
  return intent?.mode || "general";
}

function extractNexusEntities(input, mode = "") {
  const parsed = parseNexusCommand(input) || {};
  return {
    mode: mode || parsed.mode || "general",
    collectedInfo: parsed.collectedInfo || [],
    missingInfo: parsed.missingInfo || [],
    relatedRecords: parsed.relatedRecords || []
  };
}

function buildNexusMission(intent, context = {}) {
  return buildNexusAgenticMissionFromIntent(intent, context.command || intent?.userGoal || "");
}

function continueNexusMission(criteria = {}) {
  return continueNexusAgenticMission(criteria.command || "Continue current mission.");
}

function updateNexusMission(missionId = "", updates = {}) {
  const mission = updateNexusMemory(missionId, updates);
  return mission ? setNexusAgenticCommandResult(mission, "Mission updated locally. No external system was changed.") : false;
}

function cancelNexusMission(missionId = "", reason = "") {
  const mission = updateNexusMemory(missionId, {
    status: "canceled",
    executionStatus: "canceled_locally",
    nextStep: reason || "Mission canceled locally."
  });
  return mission ? setNexusAgenticCommandResult(mission, "Mission canceled locally. No external action occurred.") : cancelNexusAgenticMission(reason);
}

function prepareNexusAction(mission) {
  return {
    actionId: `nexus-action-${Date.now()}`,
    missionId: mission?.id || "",
    plan: mission?.actionPlan || [],
    confirmationRequired: Boolean(mission?.confirmationRequired),
    executionAuthority: false,
    noExternalExecutionAuthorized: true
  };
}

function confirmNexusAction(missionId = "") {
  const mission = nexusAgenticCommandMissions.find(item => item.id === missionId) || nexusAgenticCommandMissions[0] || null;
  if (mission) nexusActiveWorkflowState = { agenticMission: mission };
  return confirmNexusAgenticMission("Confirm current mission.");
}

function executeSafeLocalAction(action = {}) {
  return {
    ok: true,
    status: "completed_local",
    action,
    happened: "Safe local action completed.",
    didNot: "No provider, payment, call, message, booking, dispatch, diagnosis, prescription, location, camera, or external handoff occurred.",
    noExternalExecutionAuthorized: true
  };
}

function prepareProviderHandoff(action = {}) {
  return {
    ok: true,
    status: "blocked_missing_provider",
    action,
    providerReadiness: "provider_credentials_or_confirmation_required",
    message: "Provider handoff can be prepared locally, but it cannot be sent without provider configuration, consent, confirmation, audit, and verification.",
    noFakeProviderContact: true
  };
}

function recordNexusReceipt(event = {}) {
  const mission = nexusAgenticCommandMissions[0] || { id: "nexus-receipt-only", title: "Nexus receipt", nextStep: "Review local receipt.", executionStatus: "completed_local" };
  return nexusAgenticCommandReceipt(mission, event.happened || "Local event recorded.", event.didNot || "No external action occurred.");
}

function verifyNexusOutcome(missionId = "") {
  const mission = nexusAgenticCommandMissions.find(item => item.id === missionId) || nexusAgenticCommandMissions[0] || null;
  if (!mission) return { ok: false, status: "no_mission", message: "No mission is available to verify." };
  const receipt = mission.receipts?.[0] || nexusAgenticCommandLocalMemory.receipts?.find?.(item => item.missionId === mission.id) || null;
  return {
    ok: true,
    status: receipt ? "verified_local_record" : "verification_pending",
    missionId: mission.id,
    receiptId: receipt?.id || "",
    happened: receipt?.happened || "Mission exists locally.",
    didNot: receipt?.didNot || "No external action was recorded.",
    nextStep: mission.nextStep,
    noFakeSuccess: true
  };
}

function renderNexusMissionWorkspace(mission) {
  if (mission?.id) {
    nexusActiveWorkflowState = { agenticMission: mission };
  }
  return renderNexusAgenticMissionWorkspace();
}

function routeNexusCommand(input, source = "text") {
  return runNexusAgenticCommandRuntime(input, { source });
}

if (typeof window !== "undefined") {
  window.runNexusAgenticCommandRuntime = runNexusAgenticCommandRuntime;
  window.parseNexusAgenticCommandIntent = parseNexusAgenticCommandIntent;
  window.parseNexusCommand = parseNexusCommand;
  window.resolveNexusIntent = resolveNexusIntent;
  window.classifyNexusMode = classifyNexusMode;
  window.extractNexusEntities = extractNexusEntities;
  window.buildNexusMission = buildNexusMission;
  window.routeNexusCommand = routeNexusCommand;
  window.getNexusMemory = getNexusMemory;
}

function runNexusStandardUserHomeLocalCommand(command = "") {
  const normalized = String(command || "").trim();
  if (!normalized) return false;
  const normalizedLower = normalized.toLowerCase();
  if (isNexusPersistentMemoryCommand(normalized) && runNexusAgenticCommandRuntime(normalized, { source: "text" })) return true;
  if (isNexusPredictiveMaturityCommand(normalized) && runNexusAgenticCommandRuntime(normalized, { source: "text" })) return true;
  if (isNexusMultiDomainPredictiveCommand(normalized) && runNexusAgenticCommandRuntime(normalized, { source: "text" })) return true;
  if (isNexusAgriculturePredictiveModelerCommand(normalized) && runNexusAgenticCommandRuntime(normalized, { source: "text" })) return true;
  if (isNexusChronicPredictiveModelerCommand(normalized) && runNexusAgenticCommandRuntime(normalized, { source: "text" })) return true;
  if (shouldNexusAgenticCommandRuntimeHandle(normalized) && runNexusAgenticCommandRuntime(normalized, { source: "text" })) return true;
  if (/\b(open command center|show command center|nexus home|open nexus home)\b/i.test(normalized)) {
    closeNexusFunctionWindow({ command: "What can Nexus do?" });
    nexusAgenticBrainLastResult = buildNexusCapabilityOverviewResult(normalized);
    renderUserWorkspace();
    return true;
  }
  if (/\b(internet services integration audit|internet integration audit|mode by mode internet|internet services audit|what modes are connected|which modes are internet integrated)\b/i.test(normalized)) {
    closeNexusFunctionWindow({ command: "Show internet services integration audit" });
    const audit = window.NexusInternetIntegrationAudit?.buildNexusInternetIntegrationAudit?.({
      demoDataLoaded: Boolean(nexusDemoDataState?.loaded)
    });
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_internet_services_integration_audit_opened",
      mode: "Internet Services Integration Audit",
      message: audit?.summary ? `Internet Services Integration Audit is open. ${audit.summary.totalModes} modes audited; ${audit.summary.missingCredentials} missing-credential categories; ${audit.summary.vendorRequired} vendor-required categories; ${audit.summary.blockedForSafety} blocked-for-safety categories.` : "Internet Services Integration Audit is open in the Activation Center.",
      preparedCards: [{ type: "internet_services_integration_audit", title: "Internet Services Integration Audit", status: "local audit view open", localOnly: true, noExecutionAuthorized: true }],
      noExecutionAuthorized: true,
      localOnly: true,
      source: "nexus_internet_services_integration_audit"
    };
    nexusActiveWorkflowState = {
      id: "resource-assistant",
      command: normalized,
      source: "typed-command",
      workflow: "activation-center",
      action: "internet-integration-audit",
      openedAt: Date.now()
    };
    saveNexusRuntimeMemory();
    renderUserWorkspace();
    return true;
  }
  if (/\b(load demo data|load sandbox data|start sandbox mode|seed demo data)\b/i.test(normalized)) {
    seedNexusDemoData();
    return true;
  }
  if (/\b(reset demo data|clear demo data|reset sandbox data|clear sandbox records)\b/i.test(normalized)) {
    resetNexusDemoData();
    return true;
  }
  if (/\b(show demo records|open demo records|show sandbox records|open sandbox records|show demo missions|open demo missions)\b/i.test(normalized)) {
    if (!nexusDemoDataState?.loaded) seedNexusDemoData();
    nexusDemoDataVisible = true;
    saveNexusDemoDataState();
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_demo_sandbox_records_visible",
      mode: "Demo Sandbox Records",
      message: "Demo sandbox records and missions are visible. All records are fictional and no external action occurred.",
      preparedCards: [{ type: "demo_sandbox_records", title: "Demo records", status: "visible", localOnly: true, noExecutionAuthorized: true, demo: true }],
      noExecutionAuthorized: true,
      localOnly: true,
      source: "nexus_demo_sandbox"
    };
    renderUserWorkspace();
    return true;
  }
  if (/\b(hide demo records|hide sandbox records|hide demo missions)\b/i.test(normalized)) {
    nexusDemoDataVisible = false;
    saveNexusDemoDataState();
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_demo_sandbox_records_hidden",
      mode: "Demo Sandbox Records",
      message: "Demo sandbox records are hidden. Sandbox data remains separated and resettable.",
      preparedCards: [{ type: "demo_sandbox_records", title: "Demo records", status: "hidden", localOnly: true, noExecutionAuthorized: true, demo: true }],
      noExecutionAuthorized: true,
      localOnly: true,
      source: "nexus_demo_sandbox"
    };
    renderUserWorkspace();
    return true;
  }
  const demoModeCommand = normalized.match(/\b(?:open|show)\s+(health|chronic care|rpm|rtm|agriculture|marketplace|agritrade|logistics|maps|workforce|jobs|learning|training|drone|communications|media|provider readiness|pharmacy|mobile clinic)\s+(?:demo|sandbox)(?:\s+records)?\b/i);
  if (demoModeCommand) {
    if (!nexusDemoDataState?.loaded) seedNexusDemoData();
    nexusDemoDataVisible = true;
    const requested = demoModeCommand[1].toLowerCase();
    const modeMap = {
      health: "health",
      "chronic care": "health",
      rpm: "health",
      rtm: "health",
      pharmacy: "health",
      "mobile clinic": "health",
      agriculture: "agriculture",
      marketplace: "marketplace",
      agritrade: "marketplace",
      logistics: "logistics",
      maps: "logistics",
      workforce: "workforce",
      jobs: "workforce",
      learning: "learning",
      training: "learning",
      drone: "drone",
      communications: "communications",
      media: "communications",
      "provider readiness": "providerActivation"
    };
    const recordSection = modeMap[requested] || "health";
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_demo_sandbox_mode_records_visible",
      mode: "Demo Sandbox Records",
      message: `${recordSection} demo sandbox records are visible. No live provider, payment, message, shipment, marketplace, health, pharmacy, mobile clinic, or drone action occurred.`,
      preparedCards: [{
        type: "demo_sandbox_mode_records",
        title: `${recordSection} demo records`,
        status: "visible",
        localOnly: true,
        noExecutionAuthorized: true,
        demo: true
      }],
      noExecutionAuthorized: true,
      localOnly: true,
      source: "nexus_demo_sandbox"
    };
    saveNexusDemoDataState();
    renderUserWorkspace();
    requestAnimationFrame(() => document.querySelector(`[data-nexus-demo-record-section="${recordSection}"]`)?.scrollIntoView?.({ block: "center" }));
    return true;
  }
  if (routeNexusIntentDrivenWorkflowCommand(normalized, { source: "standard-user-intent-router" })) return true;
  if (isNexusPersistentOperationsCommand(normalized)) {
    runNexusPersistentOperationsCommand(normalized, { source: "operations-command" }).catch(error => {
      nexusAgenticBrainLastResult = {
        ok: false,
        status: "nexus_operations_memory_error",
        mode: "Operations Memory",
        message: error.message || "Operations memory needs attention.",
        preparedCards: [],
        noExecutionAuthorized: true,
        localOnly: true
      };
      renderUserWorkspace();
    });
    return true;
  }
  const requestedHomeModeId = detectNexusHomeModePanelId(normalized);
  if (requestedHomeModeId && nexusWorkflowDefinition(requestedHomeModeId, normalized)) {
    return openNexusWorkflow(requestedHomeModeId, { command: normalized, source: "home-mode-command" });
  }
  if (/\b(show recent workflows|recent workflows|continue where you left off)\b/i.test(normalized)) {
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_recent_workflows_visible",
      mode: "Recent workflows",
      message: nexusRecentWorkflows.length ? "Recent workflows are visible in the Command Center." : "No recent workflows yet. Choose a service to begin.",
      preparedCards: nexusRecentWorkflows.map(item => ({ type: "recent_workflow", title: item.title, status: item.status, localOnly: true })),
      noExecutionAuthorized: true,
      localOnly: true
    };
    renderUserWorkspace();
    return true;
  }
  if (/\b(continue mobile clinic|continue pharmacy|continue crop|continue agriculture|continue telehealth|continue logistics|continue training|continue live knowledge|continue workforce)\b/i.test(normalized)) {
    const match = nexusRecentWorkflows.find(item => normalizedLower.includes(item.title.toLowerCase().split(" ")[0]) || normalizedLower.includes(item.id.replace(/-/g, " "))) || nexusRecentWorkflows[0];
    if (match) return openNexusWorkflow(match.id, { command: normalized, source: "continue-recent-command" });
  }
  if (/\b(start guided|guided intake|guided mode)\b/i.test(normalized)) {
    const workflowId = normalizeNexusWorkflowId("", normalized) || detectNexusHomeModePanelId(normalized) || nexusActiveWorkflowState?.id || "mobile-clinic";
    return openNexusWorkflow(workflowId, { command: normalized, source: "guided-command", guidedMode: true });
  }
  if (/\b(use low bandwidth mode|turn on low bandwidth|low-bandwidth mode)\b/i.test(normalized)) {
    nexusLowBandwidthMode = !/\b(turn off|disable|standard visual)\b/i.test(normalized);
    saveNexusRuntimeMemory();
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_low_bandwidth_preference_updated",
      mode: "Low-bandwidth mode",
      message: nexusLowBandwidthMode ? "Low-bandwidth mode is on. Nexus will emphasize compact text-first workflows." : "Low-bandwidth mode is off.",
      preparedCards: [{ type: "low_bandwidth_preference", title: "Low-bandwidth mode", status: nexusLowBandwidthMode ? "on" : "off", localOnly: true }],
      noExecutionAuthorized: true,
      localOnly: true
    };
    renderUserWorkspace();
    return true;
  }
  const roleCommand = normalized.match(/\bset role to (standard user|provider|vendor|admin|trainer|agriculture expert|clinic staff)\b/i);
  if (roleCommand) {
    const requested = roleCommand[1].replace(/\b\w/g, letter => letter.toUpperCase());
    nexusUserExperienceRole = NEXUS_UX_ROLES.find(role => role.toLowerCase() === requested.toLowerCase()) || "Standard User";
    saveNexusRuntimeMemory();
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_role_view_updated",
      mode: "Role-aware view",
      message: `${nexusUserExperienceRole} view selected. This is a UX filter, not authentication.`,
      preparedCards: [{ type: "role_aware_view", title: nexusUserExperienceRole, status: "selected", localOnly: true }],
      noExecutionAuthorized: true,
      localOnly: true
    };
    renderUserWorkspace();
    return true;
  }
  if (/\b(close this window|close window)\b/i.test(normalized)) return closeNexusFunctionWindow({ command: "What can Nexus do?" });
  if (/\b(minimize this window|minimize window)\b/i.test(normalized)) return minimizeNexusFunctionWindow();
  if (/\b(restore last window|restore window)\b/i.test(normalized)) return restoreNexusFunctionWindow();
  if (/\b(go back|back to home)\b/i.test(normalized)) return closeNexusFunctionWindow({ command: "What can Nexus do?" });
  if (/\b(show action receipt|what did nexus do|what did you do)\b/i.test(normalized)) {
    const packet = nexusPreparedPackets[0] || null;
    const entry = nexusActionHistory[0] || null;
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_action_receipt_visible",
      mode: "Action receipt",
      message: entry?.resultMessage || "No action receipt yet. Prepare or queue a packet to create one.",
      preparedCards: [{ type: "nexus_action_receipt", title: packet?.workflowLabel || "Action receipt", status: entry?.outcomeStatus || "none", localOnly: true }],
      noExecutionAuthorized: true,
      localOnly: true
    };
    renderUserWorkspace();
    return true;
  }
  if (!isNexusLiveKnowledgeQuestion(normalized) && handleNexusUniversalNavigationCommand(normalized, {
    inputType: "text",
    source: "standard-user-local-command",
    currentWorkspaceId: nexusCurrentUniversalWorkspaceId()
  })) {
    return true;
  }
  if (/\b(clear local sensitive data|clear sensitive data|reset local nexus data)\b/i.test(normalized)) {
    clearNexusSensitiveLocalData();
    return true;
  }
  if (/\b(continue my last workflow|continue last workflow|resume workflow|continue workflow)\b/i.test(normalized)) {
    const lastId = nexusActiveWorkflowState?.id || nexusPreparedPackets[0]?.workflowId || nexusActionHistory[0]?.workflowId || "";
    if (lastId && nexusWorkflowDefinition(lastId, normalized)) return openNexusWorkflow(lastId, { command: normalized, source: "continue-command" });
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "no_workflow_to_continue",
      mode: "Nexus continuation",
      message: "There is no local workflow to continue yet. Choose a workflow card or tell Nexus what you need.",
      preparedCards: [],
      noExecutionAuthorized: true,
      localOnly: true,
      source: "nexus_runtime_memory"
    };
    renderUserWorkspace();
    return true;
  }
  if (/\b(show pending actions|show my tasks|pending actions|queued actions|show queued)\b/i.test(normalized)) return showNexusRuntimeList("pending");
  if (/\b(show failed actions|failed actions)\b/i.test(normalized)) return showNexusRuntimeList("failed");
  if (/\b(show follow-up needed|follow up needed|follow-up needed)\b/i.test(normalized)) return showNexusRuntimeList("follow-up");
  const runtimeIntent = resolveNexusIntent(normalized);
  if (runtimeIntent.type === "activation-center" || runtimeIntent.type === "command-center" || runtimeIntent.type === "review-queue") {
    nexusActiveWorkflowState = {
      id: "resource-assistant",
      command: normalized,
      source: "typed-command",
      workflow: runtimeIntent.type,
      action: "open-status",
      openedAt: Date.now()
    };
    saveNexusRuntimeMemory();
    nexusAgenticBrainLastResult = {
      ok: true,
      status: `nexus_${runtimeIntent.type}_opened`,
      mode: "Nexus Command Center",
      message: `${runtimeIntent.type.replace(/-/g, " ")} is open in Review workspace details. No external action was executed.`,
      preparedCards: [{ type: runtimeIntent.type, title: runtimeIntent.type.replace(/-/g, " "), status: "local runtime view open", localOnly: true }],
      noExecutionAuthorized: true,
      localOnly: true,
      source: "nexus_agent_runtime"
    };
    renderUserWorkspace();
    scheduleNexusActiveWorkflowFocus({ instant: true });
    return true;
  }
  if (runtimeIntent.capabilityId) {
    return openNexusCapability(runtimeIntent.capabilityId, { command: normalized, source: "typed-command", sourceSurface: "standard_user_home" });
  }
  if (shouldNexusGlobalAssistantBrainHandle(normalized)) {
    const result = buildNexusGlobalAssistantBrainResult(normalized);
    const workflowIdFromPlan = result.preparedCards?.[0]?.globalAssistantBrainPlan?.workflowId || normalizeNexusWorkflowId("", normalized) || "resource-assistant";
    nexusActiveWorkflowState = {
      id: workflowIdFromPlan,
      command: normalized,
      source: "typed-command",
      workflow: workflowIdFromPlan,
      action: "assistant-plan",
      openedAt: Date.now()
    };
    saveNexusRuntimeMemory();
    nexusAgenticBrainLastResult = result;
    renderUserWorkspace();
    scheduleNexusActiveWorkflowFocus();
    return true;
  }
  const workflowId = normalizeNexusWorkflowId("", normalized) || detectNexusHomeModePanelId(normalized);
  if (workflowId && nexusWorkflowDefinition(workflowId, normalized)) {
    return openNexusWorkflow(workflowId, { command: normalized, source: "typed-command" });
  }
  if (isNexusCapabilityOverviewCommand(normalized) || /\b(what can nexus do|what can you do|show me nexus modes|nexus modes)\b/i.test(normalized)) {
    nexusAgenticBrainLastResult = buildNexusCapabilityOverviewResult(normalized);
    renderUserWorkspace();
    return true;
  }
  if (isNexusMediaMusicCommand(normalized) || /\b(play|open)\b.*\b(music|r&b|rnb|afrobeats?|african|amapiano|gospel|youtube|spotify|apple music)\b/i.test(normalized)) {
    return openNexusWorkflow("media", { command: normalized, source: "typed-command" });
  }
  const localHealthAccessResult = buildNexusHealthAccessPreparationResult(normalized);
  if (localHealthAccessResult) {
    const healthWorkflowId = normalizeNexusWorkflowId("", normalized) || "clinical-support";
    nexusActiveWorkflowState = {
      id: healthWorkflowId,
      command: normalized,
      source: "typed-command",
      workflow: healthWorkflowId,
      action: "health-access-prep",
      openedAt: Date.now()
    };
    saveNexusRuntimeMemory();
    nexusAgenticBrainLastResult = localHealthAccessResult;
    renderUserWorkspace();
    scheduleNexusActiveWorkflowFocus();
    return true;
  }
  return false;
}

function renderNexusActiveWorkSummary() {
  const tasks = Array.isArray(nexusAgenticBrainTasks) ? nexusAgenticBrainTasks.filter(task => !["completed", "cancelled"].includes(task.status)) : [];
  const reminders = tasks.filter(task => task.reminderRequest || task.reminderId).length;
  const summaries = tasks.filter(task => task.providerReport).length;
  const offline = tasks.filter(task => task.type === "offline_queue").length;
  return `
    <section class="nexus-active-work-summary" data-nexus-active-work-summary="true" aria-label="${escapeHtml(translateText("Active Nexus work"))}">
      <div><strong>${escapeHtml(String(tasks.length))}</strong><span>${translateText("Active tasks")}</span></div>
      <div><strong>${escapeHtml(String(reminders))}</strong><span>${translateText("Reminders")}</span></div>
      <div><strong>${escapeHtml(String(summaries))}</strong><span>${translateText("Prepared summaries")}</span></div>
      <div><strong>${escapeHtml(String(offline))}</strong><span>${translateText("Offline queued")}</span></div>
    </section>
  `;
}

