function nexusOsShellState() {
  const profile = data?.profile || {};
  const deployment = getNexusOsActiveDeploymentProfile();
  const validation = validateNexusOsActiveDeploymentProfile();
  const displayName = profile.name || profile.displayName || "";
  const hasMission = Boolean(nexusActiveWorkflowState?.title || nexusActiveWorkflowState?.command || nexusAgenticCommandLocalMemory?.lastCommand);
  const voiceSupported = typeof window !== "undefined" && (Boolean(window.SpeechRecognition || window.webkitSpeechRecognition) || Boolean(window.speechSynthesis));
  const offline = typeof navigator !== "undefined" && navigator.onLine === false;
  return {
    deploymentState: `${deployment.displayName || "Nexus"} profile loaded`,
    domainState: `${validation.domainPackCount || 0} domain packs active`,
    userState: displayName ? "Returning user" : "Anonymous user",
    visitState: hasMission ? "Existing mission available" : "First visit ready",
    voiceState: voiceSupported ? "Voice available" : "Voice unavailable",
    connectivityState: offline ? "Offline" : "Online / local fallback",
    bandwidthState: nexusLowBandwidthMode ? "Low-bandwidth mode" : "Standard bandwidth",
    focusState: "Keyboard focus starts at Ask Nexus"
  };
}

function getNexusOsActiveDeploymentModule() {
  return typeof window !== "undefined" ? window.NexusOsAgriNexusDeploymentProfile : null;
}

function getNexusOsActiveDeploymentProfile() {
  const module = getNexusOsActiveDeploymentModule();
  if (module?.getNexusOsAgriNexusDeploymentProfile) return module.getNexusOsAgriNexusDeploymentProfile();
  return {
    deploymentId: "agrinexus",
    displayName: "AgriNexus",
    enabledDomains: [],
    enabledWorkflows: [],
    requiredPolicies: [],
    supportedLanguages: ["en"]
  };
}

function validateNexusOsActiveDeploymentProfile() {
  const module = getNexusOsActiveDeploymentModule();
  if (module?.validateAgriNexusDeploymentProfile) return module.validateAgriNexusDeploymentProfile();
  return { ok: false, domainPackCount: 0, workflowCount: 0, policyCount: 0, providerRequirementCount: 0, issues: ["profile_module_unavailable"] };
}

function validateNexusOsHealthWorkforceSafetyPack() {
  const module = typeof window !== "undefined" ? window.NexusOsHealthWorkforceSafetyPack : null;
  if (module?.validateHealthWorkforceSafetyPack) return module.validateHealthWorkforceSafetyPack();
  return { ok: false, healthWorkflowCount: 0, workforceWorkflowCount: 0, policyCount: 0, issues: ["health_workforce_safety_pack_unavailable"] };
}

function renderNexusOsDeploymentProfileSummary() {
  const deployment = getNexusOsActiveDeploymentProfile();
  const validation = validateNexusOsActiveDeploymentProfile();
  const safetyValidation = validateNexusOsHealthWorkforceSafetyPack();
  const domains = Array.isArray(deployment.enabledDomains) ? deployment.enabledDomains : [];
  const safeDomains = domains.slice(0, 6).map(domain => domain.replace(/_/g, " ")).join(", ");
  return `
    <div class="nexus-os-deployment-summary" data-nexus-os-deployment-profile="${escapeHtml(deployment.deploymentId || "unknown")}" data-nexus-os-domain-pack-count="${escapeHtml(String(validation.domainPackCount || 0))}" data-nexus-os-workflow-count="${escapeHtml(String(validation.workflowCount || 0))}" data-nexus-os-profile-valid="${validation.ok ? "true" : "false"}" data-nexus-os-health-workforce-safety="${safetyValidation.ok ? "true" : "false"}">
      <strong>${escapeHtml(translateText(deployment.displayName || "Nexus"))}</strong>
      <span>${escapeHtml(translateText("assembled from Nexus OS core, domain packs, provider requirements, policies, and deployment configuration"))}</span>
      <small>${escapeHtml(translateText(`Enabled packs: ${safeDomains || "configured by deployment profile"}.`))}</small>
      <small>${escapeHtml(translateText(`Health/workforce safety: ${safetyValidation.healthWorkflowCount || 0} health workflows, ${safetyValidation.workforceWorkflowCount || 0} workforce workflows, ${safetyValidation.policyCount || 0} policies.`))}</small>
    </div>
  `;
}

function renderNexusOsApplicationShellPanel() {
  const shellState = nexusOsShellState();
  const controls = [
    ["Language", "Nexus, change language."],
    ["Mission history", "Nexus, show receipts."],
    ["Privacy", "Nexus, show privacy controls."],
    ["Accessibility", "Nexus, open accessibility help."],
    ["Settings", "Nexus, show language and safety settings."],
    ["Connectivity", "Nexus, show provider readiness."]
  ];
  return `
    <section class="nexus-os-shell-panel" data-nexus-os-application-shell="true" aria-label="${escapeHtml(translateText("Nexus OS shell status"))}">
      <div class="nexus-os-shell-status" data-nexus-os-shell-states="true">
        ${Object.values(shellState).map(value => `<span>${escapeHtml(translateText(value))}</span>`).join("")}
      </div>
      ${renderNexusOsDeploymentProfileSummary()}
      <div class="nexus-os-shell-actions" data-nexus-os-shell-actions="true" aria-label="${escapeHtml(translateText("Nexus shell controls"))}">
        ${controls.map(([label, command]) => `
          <button type="button" data-simple-command="${escapeHtml(command)}" data-nexus-os-shell-control="${escapeHtml(String(label).toLowerCase().replace(/[^a-z0-9]+/g, "-"))}">
            ${escapeHtml(translateText(label))}
          </button>
        `).join("")}
      </div>
      <p class="nexus-os-shell-focus-note">${escapeHtml(translateText("Speak or type naturally. Nexus opens only the workflow needed for your mission."))}</p>
    </section>
  `;
}

function renderNexusOsCalmHelper() {
  const prompts = [
    "Nexus, help me get started.",
    "Nexus, what can you do?",
    "Nexus, show my recent mission.",
    "Nexus, change language."
  ];
  return `
    <div class="nexus-os-calm-helper" aria-label="${escapeHtml(translateText("Nexus quick starts"))}">
      <span>${escapeHtml(translateText("Start with a goal. Nexus will open only what is needed."))}</span>
      ${prompts.map(prompt => `<button type="button" data-simple-command="${escapeHtml(prompt)}">${escapeHtml(translateText(prompt))}</button>`).join("")}
    </div>
  `;
}

function getNexusOsGenesisPlatformAcceptance() {
  return {
    release: "Nexus OS 1.0 Genesis Platform Edition",
    mobileHardened: true,
    tabletHardened: true,
    desktopHardened: true,
    accessibilityHardened: true,
    reducedMotionSupported: true,
    highContrastSupported: true,
    forcedColorsSupported: true,
    screenReaderSemantics: true,
    keyboardNavigation: true,
    longTranslationResilience: true,
    noFakeExecution: true,
    tenantIsolation: true,
    domainIsolation: true
  };
}

