function renderNexusUserWorkspaceSegment(label = "Nexus section", renderer = () => "") {
  try {
    return renderer();
  } catch (error) {
    return `
      <section class="nexus-render-segment-error nexus-glass-card" data-nexus-render-segment-error="${escapeHtml(label)}" data-no-live-execution="true">
        <strong>${escapeHtml(translateText(`${label} needs a safe refresh`))}</strong>
        <p>${escapeHtml(translateText(error?.message || "This local section could not render. Nexus kept the rest of the workspace available."))}</p>
        <small>${escapeHtml(translateText("No external action ran. Clear local browser records or retry after reviewing the receipt/history panel."))}</small>
      </section>
    `;
  }
}

function renderNexusActiveWorkflowWorkspaceSafe() {
  try {
    return renderNexusActiveWorkflowWorkspace();
  } catch (error) {
    return `
      <section id="nexus-workspace" class="nexus-active-workflow nexus-active-workflow-empty nexus-glass-card" data-nexus-workspace="true" data-nexus-active-workflow="none" data-execution-authority="false" data-no-live-execution="true" aria-label="${escapeHtml(translateText("Nexus active workflow"))}">
        <div class="nexus-workflow-header">
          <span class="eyebrow">${escapeHtml(translateText("Workspace"))}</span>
          <h3 id="nexusActiveWorkflowHeading" tabindex="-1">${escapeHtml(translateText("Choose a workflow to begin"))}</h3>
          <p>${escapeHtml(translateText("Nexus cleared a stale local workflow view and kept the workspace available. No external action ran."))}</p>
        </div>
      </section>
    `;
  }
}

function renderUserWorkspace() {
  const target = $("#userWorkspace");
  if (!target) return;
  ensureNexusRealProviderStatusBootstrap();
  ensureNexusOsVisualBoundaryStyles();
  const trueExperienceMode = nexusTrueExperienceMode();
  const showMission = trueExperienceMode === "mission";
  document.body.classList.add("nexus-os-visual-boundary");
  document.body.classList.toggle("nexus-low-bandwidth-mode", nexusLowBandwidthMode);
  // Static QA compatibility notes for the safer service descriptions preserved by app-behavior-audit:
  // Review farm, crop, route, and field support options.
  // Review health access options and preparation steps.
  // Preview routes, facilities, regions, and map readiness.
  // Browse options and prepare questions before any transaction.
  // Standard User copy preserved: without sending; without buyer contact, orders, or payment; Change screen and voice language.
  target.innerHTML = `
    <div class="nexus-command-center-shell nexus-shell nexus-os-startup-surface nexus-genesis-experience-root nexus-true-experience-root" data-testid="nexus-standard-user-home" data-nexus-os-standard-startup="true-conversation" data-nexus-genesis-engine-root="true" data-nexus-genesis-experience-root="true" data-nexus-true-conversational-root="true" data-nexus-standard-user-render-root="true-conversational-experience" data-nexus-true-experience-mode="${escapeHtml(trueExperienceMode)}" data-nexus-genesis-activated="${nexusGenesisExperienceActivated ? "true" : "false"}" data-nexus-genesis-core-state="${escapeHtml(normalizeNexusCoreState(nexusCoreRuntimeState.current || "idle"))}">
      <main class="nexus-command-main nexus-main" data-nexus-genesis-first-viewport="true" aria-label="${escapeHtml(translateText("Nexus"))}">
        ${trueExperienceMode === "home"
          ? renderNexusUserWorkspaceSegment("Genesis orb home", renderNexusTrueHome)
          : trueExperienceMode === "conversation"
            ? renderNexusUserWorkspaceSegment("Audio companion", renderNexusAudioCompanionExperience)
            : renderNexusUserWorkspaceSegment("Workflow workspace", renderNexusCommandCenterHero)}
        ${showMission ? renderNexusUserWorkspaceSegment("Mission workspace", renderNexusAgenticMissionWorkspace) : ""}
        ${showMission ? renderNexusUserWorkspaceSegment("Mode launcher", renderNexusModeLauncher) : ""}
        ${showMission ? renderNexusUserWorkspaceSegment("Activity receipts", renderNexusPremiumActivityReceiptsPanel) : ""}
        ${showMission ? renderNexusUserWorkspaceSegment("Memory", renderNexusPersistentMemoryPanel) : ""}
      </main>
    </div>
    <div class="nexus-command-hidden-agent-host" data-nexus-open-dialogue-agent-host="true" hidden>${renderNexusOpenDialogueAgentCard()}</div>
    <section id="userLanguagePanel" class="user-language-panel hidden" aria-label="${translateText("Choose language")}">
      <div class="user-language-header">
        <strong>${translateText("Choose language")}</strong>
        <button type="button" class="user-language-close" data-close-user-language aria-label="${translateText("Close")}">${translateText("Close")}</button>
      </div>
      <div class="user-language-buttons">
        ${[
          ["en", "English"],
          ["fr", "French"],
          ["sw", "Kiswahili"],
          ["ar", "Arabic"],
          ["pt", "Portuguese"],
          ["es", "Spanish"]
        ].map(([code, label]) => `<button type="button" class="${languageCode() === code ? "active" : ""}" data-user-language="${code}" aria-pressed="${languageCode() === code}">
          ${translateText(label)}
        </button>`).join("")}
      </div>
      <span>${translateText("Say: change language to French, Arabic, Swahili, Portuguese, Spanish, or English.")}</span>
    </section>
  `;
  bindNexusStandardUserHomeControls();
  bindNexusPermanentMicrophoneControl();
  bindNexusPrimaryVoiceControls();
  updateNexusGenesisExperienceDom();
  setTimeout(() => {
    bindNexusPermanentMicrophoneControl();
    bindNexusPrimaryVoiceControls();
    updateNexusOsUnifiedConversationDom();
    maybeStartGenesisRecognitionAfterGrantedPermission("render-user-workspace").catch(() => {});
  }, 0);
  if (!nexusPilotPlatformStatus) {
    setTimeout(() => {
      if (experienceMode === "user" && document.querySelector("[data-nexus-pilot-status-panel='true']")) {
        refreshNexusPilotPlatformStatus({ rerender: false }).catch(() => {});
      }
    }, 0);
  }
  if (!nexusPilotReviewQueue.length) {
    setTimeout(() => {
      if (experienceMode === "user" && document.querySelector("[data-nexus-review-queue='true']")) {
        refreshNexusPilotReviewQueue({ rerender: false }).catch(() => {});
      }
    }, 0);
  }
  if (!nexusKnowledgeStatus) {
    setTimeout(() => {
      if (experienceMode === "user" && document.querySelector("[data-nexus-knowledge-rail='true']")) {
        refreshNexusKnowledgeRail({ rerender: false }).catch(() => {});
      }
    }, 0);
  }
  if (!nexusKnowledgeHistory) {
    setTimeout(() => {
      if (experienceMode === "user" && document.querySelector("[data-testid='nexus-internet-resource-history']")) {
        refreshNexusInternetResourceHistory({ rerender: false }).catch(() => {});
      }
    }, 0);
  }
  ensureNexusUserTestingRuntimeBootstrap();
  if (!nexusProductionReadinessStatus) {
    setTimeout(() => {
      if (experienceMode === "user" && document.querySelector("[data-nexus-production-rails='true']")) {
        refreshNexusProductionPlatformRails({ rerender: false }).catch(() => {});
      }
    }, 0);
  }
  if (!nexusProductionRuntimeStatus || !nexusAgenticBrainStatus) {
    setTimeout(() => {
      if (experienceMode === "user" && document.querySelector("[data-nexus-agentic-brain-panel='true']")) {
        refreshNexusAgenticBrainState().catch(() => {});
      }
    }, 0);
  }
}

function renderUserAccessibilityPanel() {
  if (experienceMode !== "user") return;
  goSection("dashboard", { instant: true, scroll: false });
  const target = $("#userWorkspace");
  if (!target) return;
  const toggles = [
    { key: "largeText", label: "Large text", detail: "Makes words easier to read." },
    { key: "highContrast", label: "High contrast", detail: "Makes buttons and text stronger." },
    { key: "reducedMotion", label: "Reduce motion", detail: "Stops extra movement." },
    { key: "screenReader", label: "Screen reader", detail: "Improves labels for assistive tools." }
  ];
  target.innerHTML = `
    <section id="userAccessibilityPanel" class="user-simple-module user-accessibility-module" aria-label="${translateText("Accessibility help")}">
      <div class="user-module-nav">
        <button type="button" class="user-module-back" data-simple-section="dashboard">${translateText("Home")}</button>
        <button type="button" class="user-module-close" data-close-user-accessibility aria-label="${translateText("Close")}">${translateText("Close")}</button>
      </div>
      <span class="eyebrow">${translateText("Accessibility")}</span>
      <h2>${translateText("Make Nexus Genesis easier to use")}</h2>
      <p>${translateText("Choose what helps you see, hear, read, or move through the app. You can change this any time.")}</p>
      <div class="user-accessibility-buttons">
        ${toggles.map(item => `<button type="button" data-accessibility="${item.key}" aria-pressed="${Boolean(accessibilityPrefs[item.key])}">
          <strong>${translateText(item.label)}</strong>
          <span>${translateText(item.detail)}</span>
          <small>${translateText(accessibilityPrefs[item.key] ? "On" : "Off")}</small>
        </button>`).join("")}
      </div>
      <div class="user-module-status" role="status">${translateText("Nexus can also read aloud, show captions, and use voice commands.")}</div>
    </section>
  `;
  applyAccessibilityPrefs();
  setVoiceResponse("Accessibility help is open. Choose large text, high contrast, reduce motion, or screen reader support.", false, { allowVoiceFirst: false });
  $("#userAccessibilityPanel")?.focus?.({ preventScroll: true });
}

