function userServicePhotoHtml(type = "agent", title = "Service") {
  const photos = {
    learning: "https://images.unsplash.com/photo-1522202176988-66273c2fd55f?auto=format&fit=crop&w=900&q=70",
    workforce: "https://images.unsplash.com/photo-1521737604893-d14cc237f11d?auto=format&fit=crop&w=900&q=70",
    health: "https://images.unsplash.com/photo-1584515933487-779824d29309?auto=format&fit=crop&w=900&q=70",
    trade: "https://images.unsplash.com/photo-1500937386664-56d1dfef3854?auto=format&fit=crop&w=900&q=70",
    map: "https://images.unsplash.com/photo-1524661135-423995f22d0b?auto=format&fit=crop&w=900&q=70",
    agent: "https://images.unsplash.com/photo-1551288049-bebda4e38f71?auto=format&fit=crop&w=900&q=70",
    profile: "https://images.unsplash.com/photo-1497366811353-6870744d04b2?auto=format&fit=crop&w=900&q=70"
  };
  return `<figure class="user-service-photo-card service-photo-${escapeHtml(type)}" style="--service-photo: url('${escapeHtml(photos[type] || photos.agent)}')" aria-label="${translateText(title)}">
    <span aria-hidden="true"></span>
    <figcaption>${translateText(title)}</figcaption>
  </figure>`;
}

function userRealMapHtml(title = "Live route map") {
  const route = activeRoute();
  const country = activeCountry();
  const order = data.profile.orders?.[data.profile.orders.length - 1] || null;
  const state = shipmentTrackingState(route, order);
  const regions = (data.countries || []).map(item => item.name).slice(0, 5).join(", ");
  return `
    <div class="user-real-map-card">
      <div class="user-real-map-head">
        <div>
          <strong>${translateText(title)}</strong>
          <span>${translateText(`Regional view: ${regions || country.name}`)}</span>
        </div>
        <small>${translateText(country.risk || "Monitored")}</small>
      </div>
      <div class="shipment-tracker-strip user-tracker-strip" aria-label="${translateText("Route tracking summary")}">
        <div><strong>${translateText("Current")}</strong><span>${translateText(state.activeCheckpoint)}</span></div>
        <div><strong>${translateText("Next")}</strong><span>${translateText(state.nextCheckpoint)}</span></div>
        <div><strong>${translateText("ETA")}</strong><span>${translateText(state.eta)}</span></div>
        <div><strong>${translateText("Progress")}</strong><span>${state.progress}%</span></div>
      </div>
      <div class="shipment-progress-bar user-route-progress" aria-label="${translateText(`Route progress ${state.progress} percent`)}"><span style="width:${state.progress}%"></span></div>
      <div id="userMapCanvas" class="user-real-map" role="img" aria-label="${translateText(`Real map for ${route.name}, showing checkpoints, facilities, and route risk.`)}"></div>
      <div class="user-real-map-meta">
        <div><strong>${translateText("Region")}</strong><span>${translateText("Africa operations")}</span></div>
        <div><strong>${translateText("Route")}</strong><span>${translateText(route.name)}</span></div>
        <div><strong>${translateText("Nearby help")}</strong><span>${translateText(`${country.facilities || 0} facilities`)}</span></div>
      </div>
    </div>
  `;
}

function providerStatusById(id) {
  return (data?.providers || []).find(provider => provider.id === id) || null;
}

function isProviderConnected(id) {
  const status = String(providerStatusById(id)?.status || "").toLowerCase();
  return status === "connected" || status === "ready";
}

function mapLayerAvailability() {
  const layers = normalizedMapTileLayers();
  return [
    layers.operational?.name || "Operational map",
    layers.satellite?.name || "Satellite imagery",
    layers.labels?.name || "Country names and borders",
    layers.openStreetMap?.name || "OpenStreetMap",
    layers.humanitarian?.name || "Humanitarian street map"
  ].filter(Boolean);
}

function mapProviderReadinessModel() {
  const mapsProvider = providerStatusById("maps");
  const routingProvider = providerStatusById("routing-geocoding") || providerStatusById("trade-logistics");
  const hasConfiguredTile = Object.values(mapTileConfig?.layers || {}).some(layer => layer?.configured);
  const layerNames = mapLayerAvailability();
  return {
    layerNames,
    tileConfigLabel: hasConfiguredTile ? "Public map tiles configured" : "Using local/default public tile templates",
    tileConfigDetail: hasConfiguredTile
      ? "Map tile URLs and attribution are coming from the server public config."
      : "The map is using built-in public tile templates until production tiles are selected.",
    routingLabel: isProviderConnected("routing-geocoding") || isProviderConnected("trade-logistics") ? "Routing provider connected" : "Routing provider not connected",
    routingDetail: isProviderConnected("routing-geocoding") || isProviderConnected("trade-logistics")
      ? (routingProvider?.detail || "Provider status says routing or logistics support is connected.")
      : "Nexus can preview route context, but it will not call navigation or routing providers yet.",
    locationLabel: "Live location requires explicit permission",
    locationDetail: "Nexus will not ask for browser location or start tracking unless you choose an explicit tracking action.",
    offlineLabel: "Offline map cache not enabled",
    offlineDetail: "The app shell can work offline, but third-party map tiles still require network access.",
    vectorLabel: "Vector map engine not enabled",
    vectorDetail: "Leaflet raster tiles remain active. MapLibre/vector migration is a future decision.",
    providerDetail: mapsProvider?.detail || "Map provider status is read from current app readiness."
  };
}

function userMapProviderReadinessHtml() {
  const model = mapProviderReadinessModel();
  const items = [
    { label: "Layers", value: model.layerNames.join(", ") },
    { label: "Tiles", value: `${model.tileConfigLabel}. ${model.tileConfigDetail}` },
    { label: "Routing", value: `${model.routingLabel}. ${model.routingDetail}` },
    { label: "Location", value: model.locationDetail },
    { label: "Offline", value: model.offlineDetail },
    { label: "Engine", value: model.vectorDetail }
  ];
  return `
    <div id="userMapProviderReadiness" class="user-map-provider-readiness" aria-label="${translateText("Map provider readiness")}">
      <div class="user-map-provider-head">
        <strong>${translateText("Map readiness")}</strong>
        <span>${translateText("Preview only")}</span>
      </div>
      <p>${translateText("These map tools can show public tile layers, saved routes, checkpoints, facilities, and shipment context. Live routing, navigation, location sharing, and offline map tiles need future provider setup or explicit permission.")}</p>
      <div class="user-map-provider-grid">
        ${items.map(item => `<div><strong>${translateText(item.label)}</strong><span>${translateText(item.value)}</span></div>`).join("")}
      </div>
      ${userPreviewActionsHtml([
        { label: "Available Features", command: "Nexus, what map features are available?" },
        { label: "Show Satellite", command: "Nexus, show satellite imagery" },
        { label: "Plan Route", command: "Nexus, help me plan a route" }
      ])}
    </div>
  `;
}

function safeRoutePlanningPreviewModel(command = "") {
  const route = activeRoute();
  const country = activeCountry();
  const rawCommand = String(command || "").trim();
  const reviewFields = [
    { label: "Starting place", value: route?.origin || data.profile.activeCheckpoint || country.name },
    { label: "Destination", value: route?.destination || route?.checkpoint || "Add destination before provider routing" },
    { label: "Purpose", value: /care|clinic|health|facility/i.test(rawCommand) ? "Care or facility access" : /crop|buyer|shipment|trade|delivery/i.test(rawCommand) ? "Crop shipment or trade" : "Route review" },
    { label: "Safety concern", value: /rain|flood|risk|delay|security|road|clinic|urgent/i.test(rawCommand) ? "Review stated risk before travel" : `${route?.risk || country.risk || "Monitored"} route risk` }
  ];
  return {
    routeName: route?.name || "Saved route",
    countryName: country.name,
    status: "Review-only route plan",
    summary: "Nexus can organize the route request for review, but it will not request live location, call routing providers, open external navigation, or start travel actions from this preview.",
    providerRequirement: "Provider routing requires a connected browser-safe routing/geocoding provider and user confirmation.",
    locationRequirement: "Live start position requires an explicit location action and browser permission.",
    reviewFields
  };
}

function userSafeRoutePlanningPreviewHtml(command = "") {
  const model = safeRoutePlanningPreviewModel(command);
  return `
    <div id="userRoutePlanningPreview" class="user-route-planning-preview" aria-label="${translateText("Safe route planning preview")}">
      <div class="user-map-provider-head">
        <strong>${translateText("Route planning preview")}</strong>
        <span>${translateText(model.status)}</span>
      </div>
      <p>${translateText(model.summary)}</p>
      <div class="user-map-provider-grid user-route-planning-grid">
        ${model.reviewFields.map(item => `<div><strong>${translateText(item.label)}</strong><span>${translateText(item.value)}</span></div>`).join("")}
      </div>
      <div class="user-route-planning-guardrails">
        <div><strong>${translateText("Provider")}</strong><span>${translateText(model.providerRequirement)}</span></div>
        <div><strong>${translateText("Location")}</strong><span>${translateText(model.locationRequirement)}</span></div>
        <div><strong>${translateText("Next review")}</strong><span>${translateText(`Confirm start, destination, purpose, timing, and safety concern for ${model.routeName} in ${model.countryName}.`)}</span></div>
      </div>
      ${userPreviewActionsHtml([
        { label: "Add Start", command: "Nexus, my route starts at the pickup point" },
        { label: "Add Destination", command: "Nexus, my route destination is the buyer or clinic" },
        { label: "Review Safety", command: "Nexus, review route safety before travel" }
      ])}
    </div>
  `;
}

function userMapPreviewHtml() {
  return userRealMapHtml("Map preview");
}

